  ('44959747-7f8f-53e5-81ac-08233e8edd21', 'de-a1-articles-hund', 'vocabulary', 'der Hund', 'der hunt', 'noun', 'Der Hund ist klein.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-hund.mp3', null, 'b5d6c86e-3922-430b-897d-907ed060a047', 1, true, '{"hint":{"de":"der: Viele männliche Personen und Tiere sind der. Merke: der Hund.","en":"der: Many male people and animals use der. Remember: der Hund."},"kind":"article_noun","noun":"Hund","article":"der","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('d789e544-60b2-5d1d-9506-d03d6e3d652a', 'de-a1-articles-tisch', 'vocabulary', 'der Tisch', 'der tisch', 'noun', 'Der Tisch ist groß.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-tisch.mp3', null, '540c31f2-d763-4c93-b6d0-0b4eee94b0b1', 2, true, '{"hint":{"de":"der Tisch: ein kurzer, starker Alltagsgegenstand. Einfach als der Tisch merken.","en":"der Tisch: a short, strong everyday noun. Memorize it as der Tisch."},"kind":"article_noun","noun":"Tisch","article":"der","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('4d4314ab-a6cd-5c29-98e4-e04dcdca581b', 'de-a1-articles-zug', 'vocabulary', 'der Zug', 'der tsook', 'noun', 'Der Zug kommt.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-zug.mp3', null, '56121670-e684-47fc-9b13-b6e1572e8344', 3, true, '{"hint":{"de":"der Zug: kurz und kraftvoll. Stell dir einen starken Zug vor: der Zug.","en":"der Zug: short and powerful. Picture a strong train: der Zug."},"kind":"article_noun","noun":"Zug","article":"der","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('7cd5b995-52f5-51dc-81a6-0d25e6ac2711', 'de-a1-articles-schluessel', 'vocabulary', 'der Schlüssel', 'der SHLÜS-sel', 'noun', 'Der Schlüssel ist hier.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-schluessel.mp3', null, '1a7c7a3f-9efb-4b03-8518-5fda94814e16', 4, true, '{"hint":{"de":"Endung -el ist oft der. Merke: der Schlüssel.","en":"Words ending in -el are often der. Remember: der Schlüssel."},"kind":"article_noun","noun":"Schlüssel","article":"der","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('b6383b12-e5ef-5660-a988-129804655ca0', 'de-a1-articles-loeffel', 'vocabulary', 'der Löffel', 'der LÖF-fel', 'noun', 'Der Löffel ist klein.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-loeffel.mp3', null, '5a12cfe2-8ed5-4bee-9036-4a5771e865b9', 5, true, '{"hint":{"de":"Endung -el ist oft der. Schlüssel und Löffel gehen zusammen: der.","en":"Words ending in -el are often der. Schlüssel and Löffel go together: der."},"kind":"article_noun","noun":"Löffel","article":"der","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('05530905-7ec6-5a35-a7b1-33da285392c7', 'de-a1-articles-katze', 'vocabulary', 'die Katze', 'die KAT-ze', 'noun', 'Die Katze schläft.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-katze.mp3', null, '51d5ca1c-6a87-48b3-8da2-8b295f72e4bd', 6, true, '{"hint":{"de":"Viele Wörter auf -e sind die. Katze endet auf -e: die Katze.","en":"Many words ending in -e use die. Katze ends in -e: die Katze."},"kind":"article_noun","noun":"Katze","article":"die","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('38666742-66de-5585-91f3-08ec731cfb69', 'de-a1-articles-tasche', 'vocabulary', 'die Tasche', 'die TASH-e', 'noun', 'Die Tasche ist voll.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-tasche.mp3', null, '4a63df3b-8384-4633-9f29-b6a604fffa85', 7, true, '{"hint":{"de":"Tasche endet auf -e. Das ist oft die: die Tasche.","en":"Tasche ends in -e. That is often die: die Tasche."},"kind":"article_noun","noun":"Tasche","article":"die","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('31d12d13-9892-5dec-a29e-1a9cf88d72b0', 'de-a1-articles-lampe', 'vocabulary', 'die Lampe', 'die LAM-pe', 'noun', 'Die Lampe ist hell.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-lampe.mp3', null, 'a22b45ee-e05a-498e-b84c-ae2462d55ca5', 8, true, '{"hint":{"de":"Lampe endet auf -e. Viele -e-Wörter sind die.","en":"Lampe ends in -e. Many -e words use die."},"kind":"article_noun","noun":"Lampe","article":"die","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('5827d207-9510-572e-b5b4-4830933a3915', 'de-a1-articles-uhr', 'vocabulary', 'die Uhr', 'die oor', 'noun', 'Die Uhr ist rund.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-uhr.mp3', null, 'bee7886f-1b1b-4fa4-810a-a75cd68589b4', 9, true, '{"hint":{"de":"Uhr ist eine wichtige Ausnahme ohne -e. Kurz merken: die Uhr.","en":"Uhr is an important exception without -e. Memorize: die Uhr."},"kind":"article_noun","noun":"Uhr","article":"die","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('c191b9a4-14ba-56cf-827f-a88f6687e7cf', 'de-a1-articles-tuer', 'vocabulary', 'die Tür', 'die tür', 'noun', 'Die Tür ist offen.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-tuer.mp3', null, '4959a992-5997-4ac7-86bd-00f11d732c6e', 10, true, '{"hint":{"de":"Tür und Uhr klingen kurz. Beide sind die: die Tür, die Uhr.","en":"Tür and Uhr are short words. Both use die: die Tür, die Uhr."},"kind":"article_noun","noun":"Tür","article":"die","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('f15db869-d4a4-5ed3-a533-58678224e82b', 'de-a1-articles-haus', 'vocabulary', 'das Haus', 'das hous', 'noun', 'Das Haus ist alt.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-haus.mp3', null, 'b6c82618-a967-4c0d-93dd-9c96acebf2bf', 11, true, '{"hint":{"de":"das Haus ist ein Klassiker. Stell dir ein kleines Haus vor: das Haus.","en":"das Haus is a classic. Picture a small house: das Haus."},"kind":"article_noun","noun":"Haus","article":"das","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('90ab9861-eb6a-5b29-a229-441c9e6baa3c', 'de-a1-articles-auto', 'vocabulary', 'das Auto', 'das AU-to', 'noun', 'Das Auto ist neu.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-auto.mp3', null, 'f52ad133-bf32-4285-8020-92f0c5f43512', 12, true, '{"hint":{"de":"Viele internationale Sachwörter sind das. Merke: das Auto.","en":"Many international object words use das. Remember: das Auto."},"kind":"article_noun","noun":"Auto","article":"das","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('aad5bc84-9185-5f65-abd6-b9cc1e514058', 'de-a1-articles-buch', 'vocabulary', 'das Buch', 'das bookh', 'noun', 'Das Buch ist gut.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-buch.mp3', null, '4104dad4-a18a-495e-9b1f-216e5c4c3101', 13, true, '{"hint":{"de":"Buch ist ein Ding zum Lernen. In A1: das Buch fest merken.","en":"Buch is a learning object. For A1, memorize: das Buch."},"kind":"article_noun","noun":"Buch","article":"das","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
  ('3ca9109a-fed8-517d-9f25-9287b13d47cc', 'de-a1-articles-fenster', 'vocabulary', 'das Fenster', 'das FENS-ter', 'noun', 'Das Fenster ist offen.', null, 'de-a1-articles', 'beginner', null, 'https://pqnfiqczcxnwaenylysb.supabase.co/storage/v1/object/public/language-cards/audio/de-a1/basics-articles-20260705152000/de-a1-articles-fenster.mp3', null, '43b8aec0-3f52-4a82-be2d-3b8925c5bca3', 14, true, '{"hint":{"de":"Viele Wörter auf -er sind der, aber Fenster ist wichtig: das Fenster.","en":"Many -er words use der, but Fenster is important: das Fenster."},"kind":"article_noun","noun":"Fenster","article":"das","lesson_slug":"de-a1-basics-articles","learn_language":"de"}'::jsonb),
