insert into language_cards_card_translations (card_id, lang_code, translation, example_translation, hint) values
  ('05530905-7ec6-5a35-a7b1-33da285392c7', 'de', 'die Katze', 'Die Katze schläft.', 'Viele Wörter auf -e sind die. Katze endet auf -e: die Katze.'),
  ('05530905-7ec6-5a35-a7b1-33da285392c7', 'en', 'the cat', 'Die Katze schläft.', 'Many words ending in -e use die. Katze ends in -e: die Katze.'),
  ('17a7f6df-2123-5de1-a229-f0908861f9b8', 'de', 'das Mädchen', 'Das Mädchen lacht.', 'Endung -chen ist immer das. Deshalb: das Mädchen.'),
  ('17a7f6df-2123-5de1-a229-f0908861f9b8', 'en', 'the girl', 'Das Mädchen lacht.', 'The ending -chen always uses das. So: das Mädchen.'),
  ('31d12d13-9892-5dec-a29e-1a9cf88d72b0', 'de', 'die Lampe', 'Die Lampe ist hell.', 'Lampe endet auf -e. Viele -e-Wörter sind die.'),
  ('31d12d13-9892-5dec-a29e-1a9cf88d72b0', 'en', 'the lamp', 'Die Lampe ist hell.', 'Lampe ends in -e. Many -e words use die.'),
  ('38666742-66de-5585-91f3-08ec731cfb69', 'de', 'die Tasche', 'Die Tasche ist voll.', 'Tasche endet auf -e. Das ist oft die: die Tasche.'),
  ('38666742-66de-5585-91f3-08ec731cfb69', 'en', 'the bag', 'Die Tasche ist voll.', 'Tasche ends in -e. That is often die: die Tasche.'),
  ('3ca9109a-fed8-517d-9f25-9287b13d47cc', 'de', 'das Fenster', 'Das Fenster ist offen.', 'Viele Wörter auf -er sind der, aber Fenster ist wichtig: das Fenster.'),
  ('3ca9109a-fed8-517d-9f25-9287b13d47cc', 'en', 'the window', 'Das Fenster ist offen.', 'Many -er words use der, but Fenster is important: das Fenster.'),
  ('44959747-7f8f-53e5-81ac-08233e8edd21', 'de', 'der Hund', 'Der Hund ist klein.', 'der: Viele männliche Personen und Tiere sind der. Merke: der Hund.'),
  ('44959747-7f8f-53e5-81ac-08233e8edd21', 'en', 'the dog', 'Der Hund ist klein.', 'der: Many male people and animals use der. Remember: der Hund.'),
  ('4d4314ab-a6cd-5c29-98e4-e04dcdca581b', 'de', 'der Zug', 'Der Zug kommt.', 'der Zug: kurz und kraftvoll. Stell dir einen starken Zug vor: der Zug.'),
  ('4d4314ab-a6cd-5c29-98e4-e04dcdca581b', 'en', 'the train', 'Der Zug kommt.', 'der Zug: short and powerful. Picture a strong train: der Zug.'),
  ('5827d207-9510-572e-b5b4-4830933a3915', 'de', 'die Uhr', 'Die Uhr ist rund.', 'Uhr ist eine wichtige Ausnahme ohne -e. Kurz merken: die Uhr.'),
  ('5827d207-9510-572e-b5b4-4830933a3915', 'en', 'the clock', 'Die Uhr ist rund.', 'Uhr is an important exception without -e. Memorize: die Uhr.'),
  ('7cd5b995-52f5-51dc-81a6-0d25e6ac2711', 'de', 'der Schlüssel', 'Der Schlüssel ist hier.', 'Endung -el ist oft der. Merke: der Schlüssel.'),
  ('7cd5b995-52f5-51dc-81a6-0d25e6ac2711', 'en', 'the key', 'Der Schlüssel ist hier.', 'Words ending in -el are often der. Remember: der Schlüssel.'),
  ('90ab9861-eb6a-5b29-a229-441c9e6baa3c', 'de', 'das Auto', 'Das Auto ist neu.', 'Viele internationale Sachwörter sind das. Merke: das Auto.'),
  ('90ab9861-eb6a-5b29-a229-441c9e6baa3c', 'en', 'the car', 'Das Auto ist neu.', 'Many international object words use das. Remember: das Auto.'),
  ('aad5bc84-9185-5f65-abd6-b9cc1e514058', 'de', 'das Buch', 'Das Buch ist gut.', 'Buch ist ein Ding zum Lernen. In A1: das Buch fest merken.'),
  ('aad5bc84-9185-5f65-abd6-b9cc1e514058', 'en', 'the book', 'Das Buch ist gut.', 'Buch is a learning object. For A1, memorize: das Buch.'),
  ('b6383b12-e5ef-5660-a988-129804655ca0', 'de', 'der Löffel', 'Der Löffel ist klein.', 'Endung -el ist oft der. Schlüssel und Löffel gehen zusammen: der.'),
  ('b6383b12-e5ef-5660-a988-129804655ca0', 'en', 'the spoon', 'Der Löffel ist klein.', 'Words ending in -el are often der. Schlüssel and Löffel go together: der.'),
  ('c191b9a4-14ba-56cf-827f-a88f6687e7cf', 'de', 'die Tür', 'Die Tür ist offen.', 'Tür und Uhr klingen kurz. Beide sind die: die Tür, die Uhr.'),
  ('c191b9a4-14ba-56cf-827f-a88f6687e7cf', 'en', 'the door', 'Die Tür ist offen.', 'Tür and Uhr are short words. Both use die: die Tür, die Uhr.'),
  ('d789e544-60b2-5d1d-9506-d03d6e3d652a', 'de', 'der Tisch', 'Der Tisch ist groß.', 'der Tisch: ein kurzer, starker Alltagsgegenstand. Einfach als der Tisch merken.'),
  ('d789e544-60b2-5d1d-9506-d03d6e3d652a', 'en', 'the table', 'Der Tisch ist groß.', 'der Tisch: a short, strong everyday noun. Memorize it as der Tisch.'),
  ('f15db869-d4a4-5ed3-a533-58678224e82b', 'de', 'das Haus', 'Das Haus ist alt.', 'das Haus ist ein Klassiker. Stell dir ein kleines Haus vor: das Haus.'),
  ('f15db869-d4a4-5ed3-a533-58678224e82b', 'en', 'the house', 'Das Haus ist alt.', 'das Haus is a classic. Picture a small house: das Haus.')
